const book: BibleBook = {
  id: '1john',
  name: '1 João',
  englishName: '1 John',
  testament: 'new',
  chapters: {
    1: [
      { v: 1, en: 'That which was from the beginning, that which we have heard, that which we have seen with our eyes, that which we saw, and our hands touched, concerning the Word of life', pt: 'O que era desde o princípio, o que ouvimos, o que vimos com os nossos olhos, o que contemplamos e as nossas mãos apalparam, a respeito do Verbo da vida' },
      { v: 2, en: '(and the life was revealed, and we have seen, and testify, and declare to you the life, the eternal life, which was with the Father, and was revealed to us);', pt: '(pois a vida foi manifestada, e nós a temos visto, e dela testificamos, e vos anunciamos a vida eterna, que estava com o Pai, e a nós foi manifestada);' },
      { v: 3, en: 'that which we have seen and heard we declare to you, that you also may have fellowship with us. Yes, and our fellowship is with the Father, and with his Son, Jesus Christ.', pt: 'sim, o que vimos e ouvimos, isso vos anunciamos, para que vós também tenhais comunhão conosco; e a nossa comunhão é com o Pai, e com seu Filho Jesus Cristo.' },
      { v: 4, en: 'And we write these things to you, that our joy may be fulfilled.', pt: 'Estas coisas vos escrevemos, para que o nosso gozo seja completo.' },
      { v: 5, en: 'This is the message which we have heard from him and announce to you, that God is light, and in him is no darkness at all.', pt: 'E esta é a mensagem que dele ouvimos, e vos anunciamos: que Deus é luz, e nele não há trevas nenhumas.' },
      { v: 6, en: 'If we say that we have fellowship with him and walk in the darkness, we lie, and don’t tell the truth.', pt: 'Se dissermos que temos comunhão com ele, e andarmos nas trevas, mentimos, e não praticamos a verdade;' },
      { v: 7, en: 'But if we walk in the light, as he is in the light, we have fellowship with one another, and the blood of Jesus Christ, his Son, cleanses us from all sin.', pt: 'mas, se andarmos na luz, como ele na luz está, temos comunhão uns com os outros, e o sangue de Jesus seu Filho nos purifica de todo pecado.' },
      { v: 8, en: 'If we say that we have no sin, we deceive ourselves, and the truth is not in us.', pt: 'Se dissermos que não temos pecado nenhum, enganamo-nos a nós mesmos, e a verdade não está em nós.' },
      { v: 9, en: 'If we confess our sins, he is faithful and righteous to forgive us the sins, and to cleanse us from all unrighteousness.', pt: 'Se confessarmos os nossos pecados, ele é fiel e justo para nos perdoar os pecados e nos purificar de toda injustiça.' },
      { v: 10, en: 'If we say that we haven’t sinned, we make him a liar, and his word is not in us.', pt: 'Se dissermos que não temos cometido pecado, fazemo-lo mentiroso, e a sua palavra não está em nós.' },
    ],
    2: [
      { v: 1, en: 'My little children, I write these things to you so that you may not sin. If anyone sins, we have a Counselor with the Father, Jesus Christ, the righteous.', pt: 'Meus filhinhos, estas coisas vos escrevo, para que não pequeis; mas, se alguém pecar, temos um Advogado para com o Pai, Jesus Cristo, o justo.' },
      { v: 2, en: 'And he is the atoning sacrifice for our sins, and not for ours only, but also for the whole world.', pt: 'E ele é a propiciação pelos nossos pecados, e não somente pelos nossos, mas também pelos de todo o mundo.' },
      { v: 3, en: 'This is how we know that we know him: if we keep his commandments.', pt: 'E nisto sabemos que o conhecemos; se guardamos os seus mandamentos.' },
      { v: 4, en: 'One who says, “I know him,” and doesn’t keep his commandments, is a liar, and the truth isn’t in him.', pt: 'Aquele que diz: Eu o conheço, e não guarda os seus mandamentos, é mentiroso, e nele não está a verdade;' },
      { v: 5, en: 'But whoever keeps his word, God’s love has most certainly been perfected in him. This is how we know that we are in him:', pt: 'mas qualquer que guarda a sua palavra, nele realmente se tem aperfeiçoado o amor de Deus. E nisto sabemos que estamos nele;' },
      { v: 6, en: 'he who says he remains in him ought himself also to walk just like he walked.', pt: 'aquele que diz estar nele, também deve andar como ele andou.' },
      { v: 7, en: 'Brothers, I write no new commandment to you, but an old commandment which you had from the beginning. The old commandment is the word which you heard from the beginning.', pt: 'Amados, não vos escrevo mandamento novo, mas um mandamento antigo, que tendes desde o princípio. Este mandamento antigo é a palavra que ouvistes.' },
      { v: 8, en: 'Again, I write a new commandment to you, which is true in him and in you; because the darkness is passing away, and the true light already shines.', pt: 'Contudo é um novo mandamento que vos escrevo, o qual é verdadeiro nele e em vós; porque as trevas vão passando, e já brilha a verdadeira luz.' },
      { v: 9, en: 'He who says he is in the light and hates his brother, is in the darkness even until now.', pt: 'Aquele que diz estar na luz, e odeia a seu irmão, até agora está nas trevas.' },
      { v: 10, en: 'He who loves his brother remains in the light, and there is no occasion for stumbling in him.', pt: 'Aquele que ama a seu irmão permanece na luz, e nele não há tropeço.' },
      { v: 11, en: 'But he who hates his brother is in the darkness, and walks in the darkness, and doesn’t know where he is going, because the darkness has blinded his eyes.', pt: 'Mas aquele que odeia a seu irmão está nas trevas, e anda nas trevas, e não sabe para onde vai; porque as trevas lhe cegaram os olhos.' },
      { v: 12, en: 'I write to you, little children, because your sins are forgiven you for his name’s sake.', pt: 'Filhinhos, eu vos escrevo, porque os vossos pecados são perdoados por amor do seu nome.' },
      { v: 13, en: 'I write to you, fathers, because you know him who is from the beginning. I write to you, young men, because you have overcome the evil one. I write to you, little children, because you know the Father.', pt: 'Pais, eu vos escrevo, porque conheceis aquele que é desde o princípio. Jovens, eu vos escrevo, porque vencestes o Maligno.' },
      { v: 14, en: 'I have written to you, fathers, because you know him who is from the beginning. I have written to you, young men, because you are strong, and the word of God remains in you, and you have overcome the evil one.', pt: 'Eu vos escrevi, meninos, porque conheceis o Pai. Eu vos escrevi, pais, porque conheceis aquele que é desde o princípio. Eu escrevi, jovens, porque sois fortes, e a palavra de Deus permanece em vós, e já vencestes o Maligno.' },
      { v: 15, en: 'Don’t love the world or the things that are in the world. If anyone loves the world, the Father’s love isn’t in him.', pt: 'Não ameis o mundo, nem o que há no mundo. Se alguém ama o mundo, o amor do Pai não está nele.' },
      { v: 16, en: 'For all that is in the world, the lust of the flesh, the lust of the eyes, and the pride of life, isn’t the Father’s, but is the world’s.', pt: 'Porque tudo o que há no mundo, a concupiscência da carne, a concupiscência dos olhos e a soberba da vida, não vem do Pai, mas sim do mundo.' },
      { v: 17, en: 'The world is passing away with its lusts, but he who does God’s will remains forever.', pt: 'Ora, o mundo passa, e a sua concupiscência; mas aquele que faz a vontade de Deus, permanece para sempre.' },
      { v: 18, en: 'Little children, these are the end times, and as you heard that the Antichrist is coming, even now many antichrists have arisen. By this we know that it is the final hour.', pt: 'Filhinhos, esta é a última hora; e, conforme ouvistes que vem o anticristo, já muitos anticristos se têm levantado; por onde conhecemos que é a última hora.' },
      { v: 19, en: 'They went out from us, but they didn’t belong to us; for if they had belonged to us, they would have continued with us. But they left, that they might be revealed that none of them belong to us.', pt: 'Saíram dentre nós, mas não eram dos nossos; porque, se fossem dos nossos, teriam permanecido conosco; mas todos eles saíram para que se manifestasse que não são dos nossos.' },
      { v: 20, en: 'You have an anointing from the Holy One, and you all have knowledge.', pt: 'Ora, vós tendes a unção da parte do Santo, e todos tendes conhecimento.' },
      { v: 21, en: 'I have not written to you because you don’t know the truth, but because you know it, and because no lie is of the truth.', pt: 'Não vos escrevi porque não soubésseis a verdade, mas porque a sabeis, e porque nenhuma mentira vem da verdade.' },
      { v: 22, en: 'Who is the liar but he who denies that Jesus is the Christ? This is the Antichrist, he who denies the Father and the Son.', pt: 'Quem é o mentiroso, senão aquele que nega que Jesus é o Cristo? Esse mesmo é o anticristo, esse que nega o Pai e o Filho.' },
      { v: 23, en: 'Whoever denies the Son, the same doesn’t have the Father. He who confesses the Son has the Father also.', pt: 'Qualquer que nega o Filho, também não tem o Pai; aquele que confessa o Filho, tem também o Pai.' },
      { v: 24, en: 'Therefore, as for you, let that remain in you which you heard from the beginning. If that which you heard from the beginning remains in you, you also will remain in the Son, and in the Father.', pt: 'Portanto, o que desde o princípio ouvistes, permaneça em vós. Se em vós permanecer o que desde o princípio ouvistes, também vós permanecereis no Filho e no Pai.' },
      { v: 25, en: 'This is the promise which he promised us, the eternal life.', pt: 'E esta é a promessa que ele nos fez: a vida eterna.' },
      { v: 26, en: 'These things I have written to you concerning those who would lead you astray.', pt: 'Estas coisas vos escrevo a respeito daqueles que vos querem enganar.' },
      { v: 27, en: 'As for you, the anointing which you received from him remains in you, and you don’t need for anyone to teach you. But as his anointing teaches you concerning all things, and is true, and is no lie, and even as it taught you, you will remain in him.', pt: 'E quanto a vós, a unção que dele recebestes fica em vós, e não tendes necessidade de que alguém vos ensine; mas, como a sua unção vos ensina a respeito de todas as coisas, e é verdadeira, e não é mentira, como vos ensinou ela, assim nele permanecei.' },
      { v: 28, en: 'Now, little children, remain in him, that when he appears, we may have boldness, and not be ashamed before him at his coming.', pt: 'E agora, filhinhos, permanecei nele; para que, quando ele se manifestar, tenhamos confiança, e não fiquemos confundidos diante dele na sua vinda.' },
      { v: 29, en: 'If you know that he is righteous, you know that everyone who practices righteousness has been born of him.', pt: 'Se sabeis que ele é justo, sabeis que todo aquele que pratica a justiça é nascido dele.' },
    ],
    3: [
      { v: 1, en: 'See how great a love the Father has given to us, that we should be called children of God! For this cause the world doesn’t know us, because it didn’t know him.', pt: 'Vede que grande amor nos tem concedido o Pai: que fôssemos chamados filhos de Deus; e nós o somos. Por isso o mundo não nos conhece; porque não conheceu a ele.' },
      { v: 2, en: 'Beloved, now we are children of God, and it is not yet revealed what we will be. But we know that, when he is revealed, we will be like him; for we will see him just as he is.', pt: 'Amados, agora somos filhos de Deus, e ainda não é manifesto o que havemos de ser. Mas sabemos que, quando ele se manifestar, seremos semelhantes a ele; porque assim como é, o veremos.' },
      { v: 3, en: 'Everyone who has this hope set on him purifies himself, even as he is pure.', pt: 'E todo o que nele tem esta esperança, purifica-se a si mesmo, assim como ele é puro.' },
      { v: 4, en: 'Everyone who sins also commits lawlessness. Sin is lawlessness.', pt: 'Todo aquele que vive habitualmente no pecado também vive na rebeldia, pois o pecado é rebeldia.' },
      { v: 5, en: 'You know that he was revealed to take away our sins, and in him is no sin.', pt: 'E bem sabeis que ele se manifestou para tirar os pecados; e nele não há pecado.' },
      { v: 6, en: 'Whoever remains in him doesn’t sin. Whoever sins hasn’t seen him and doesn’t know him.', pt: 'Todo o que permanece nele não vive pecando; todo o que vive pecando não o viu nem o conhece.' },
      { v: 7, en: 'Little children, let no one lead you astray. He who does righteousness is righteous, even as he is righteous.', pt: 'Filhinhos, ninguém vos engane; quem pratica a justiça é justo, assim como ele é justo;' },
      { v: 8, en: 'He who sins is of the devil, for the devil has been sinning from the beginning. To this end the Son of God was revealed: that he might destroy the works of the devil.', pt: 'quem comete pecado é do Diabo; porque o Diabo peca desde o princípio. Para isto o Filho de Deus se manifestou: para destruir as obras do Diabo.' },
      { v: 9, en: 'Whoever is born of God doesn’t commit sin, because his seed remains in him; and he can’t sin, because he is born of God.', pt: 'Aquele que é nascido de Deus não peca habitualmente; porque a semente de Deus permanece nele, e não pode continuar no pecado, porque é nascido de Deus.' },
      { v: 10, en: 'In this the children of God are revealed, and the children of the devil. Whoever doesn’t do righteousness is not of God, neither is he who doesn’t love his brother.', pt: 'Nisto são manifestos os filhos de Deus, e os filhos do Diabo: quem não pratica a justiça não é de Deus, nem o que não ama a seu irmão.' },
      { v: 11, en: 'For this is the message which you heard from the beginning, that we should love one another;', pt: 'Porque esta é a mensagem que ouvistes desde o princípio, que nos amemos uns aos outros,' },
      { v: 12, en: 'unlike Cain, who was of the evil one, and killed his brother. Why did he kill him? Because his deeds were evil, and his brother’s righteous.', pt: 'não sendo como Caim, que era do Maligno, e matou a seu irmão. E por que o matou? Porque as suas obras eram más e as de seu irmão justas.' },
      { v: 13, en: 'Don’t be surprised, my brothers, if the world hates you.', pt: 'Meus irmãos, não vos admireis se o mundo vos odeia.' },
      { v: 14, en: 'We know that we have passed out of death into life, because we love the brothers. He who doesn’t love his brother remains in death.', pt: 'Nós sabemos que já passamos da morte para a vida, porque amamos os irmãos. Quem não ama permanece na morte.' },
      { v: 15, en: 'Whoever hates his brother is a murderer, and you know that no murderer has eternal life remaining in him.', pt: 'Todo o que odeia a seu irmão é homicida; e vós sabeis que nenhum homicida tem a vida eterna permanecendo nele.' },
      { v: 16, en: 'By this we know love, because he laid down his life for us. And we ought to lay down our lives for the brothers.', pt: 'Nisto conhecemos o amor: que Cristo deu a sua vida por nós; e nós devemos dar a vida pelos irmãos.' },
      { v: 17, en: 'But whoever has the world’s goods, and sees his brother in need, and closes his heart of compassion against him, how does God’s love remain in him?', pt: 'Quem, pois, tiver bens do mundo, e, vendo o seu irmão necessitando, lhe fechar o seu coração, como permanece nele o amor de Deus?' },
      { v: 18, en: 'My little children, let’s not love in word only, or with the tongue only, but in deed and truth.', pt: 'Filhinhos, não amemos de palavra, nem de língua, mas por obras e em verdade.' },
      { v: 19, en: 'And by this we know that we are of the truth, and persuade our hearts before him,', pt: 'Nisto conheceremos que somos da verdade, e diante dele tranqüilizaremos o nosso coração;' },
      { v: 20, en: 'because if our heart condemns us, God is greater than our heart, and knows all things.', pt: 'porque se o coração nos condena, maior é Deus do que o nosso coração, e conhece todas as coisas.' },
      { v: 21, en: 'Beloved, if our hearts don’t condemn us, we have boldness toward God;', pt: 'Amados, se o coração não nos condena, temos confiança para com Deus;' },
      { v: 22, en: 'and whatever we ask, we receive from him, because we keep his commandments and do the things that are pleasing in his sight.', pt: 'e qualquer coisa que lhe pedirmos, dele a receberemos, porque guardamos os seus mandamentos, e fazemos o que é agradável à sua vista.' },
      { v: 23, en: 'This is his commandment, that we should believe in the name of his Son, Jesus Christ, and love one another, even as he commanded.', pt: 'Ora, o seu mandamento é este, que creiamos no nome de seu Filho Jesus Cristo, e nos amemos uns aos outros, como ele nos ordenou.' },
      { v: 24, en: 'He who keeps his commandments remains in him, and he in him. By this we know that he remains in us, by the Spirit which he gave us.', pt: 'Quem guarda os seus mandamentos, em Deus permanece e Deus nele. E nisto conhecemos que ele permanece em nós: pelo Espírito que nos tem dado.' },
    ],
    4: [
      { v: 1, en: 'Beloved, don’t believe every spirit, but test the spirits, whether they are of God, because many false prophets have gone out into the world.', pt: 'Amados, não creiais a todo espírito, mas provai se os espíritos vêm de Deus; porque muitos falsos profetas têm saído pelo mundo.' },
      { v: 2, en: 'By this you know the Spirit of God: every spirit who confesses that Jesus Christ has come in the flesh is of God,', pt: 'Nisto conheceis o Espírito de Deus: todo espírito que confessa que Jesus Cristo veio em carne é de Deus;' },
      { v: 3, en: 'and every spirit who doesn’t confess that Jesus Christ has come in the flesh is not of God, and this is the spirit of the Antichrist, of whom you have heard that it comes. Now it is in the world already.', pt: 'e todo espírito que não confessa a Jesus não é de Deus; mas é o espírito do anticristo, a respeito do qual tendes ouvido que havia de vir; e agora já está no mundo.' },
      { v: 4, en: 'You are of God, little children, and have overcome them; because greater is he who is in you than he who is in the world.', pt: 'Filhinhos, vós sois de Deus, e já os tendes vencido; porque maior é aquele que está em vós do que aquele que está no mundo.' },
      { v: 5, en: 'They are of the world. Therefore they speak of the world, and the world hears them.', pt: 'Eles são do mundo, por isso falam como quem é do mundo, e o mundo os ouve.' },
      { v: 6, en: 'We are of God. He who knows God listens to us. He who is not of God doesn’t listen to us. By this we know the spirit of truth, and the spirit of error.', pt: 'Nós somos de Deus; quem conhece a Deus nos ouve; quem não é de Deus não nos ouve. assim é que conhecemos o espírito da verdade e o espírito do erro.' },
      { v: 7, en: 'Beloved, let us love one another, for love is of God; and everyone who loves has been born of God, and knows God.', pt: 'Amados, amemo-nos uns aos outros, porque o amor é de Deus; e todo o que ama é nascido de Deus e conhece a Deus.' },
      { v: 8, en: 'He who doesn’t love doesn’t know God, for God is love.', pt: 'Aquele que não ama não conhece a Deus; porque Deus é amor.' },
      { v: 9, en: 'By this God’s love was revealed in us, that God has sent his one and only Son into the world that we might live through him.', pt: 'Nisto se manifestou o amor de Deus para conosco: em que Deus enviou seu Filho unigênito ao mundo, para que por meio dele vivamos.' },
      { v: 10, en: 'In this is love, not that we loved God, but that he loved us, and sent his Son as the atoning sacrifice for our sins.', pt: 'Nisto está o amor: não em que nós tenhamos amado a Deus, mas em que ele nos amou a nós, e enviou seu Filho como propiciação pelos nossos pecados.' },
      { v: 11, en: 'Beloved, if God loved us in this way, we also ought to love one another.', pt: 'Amados, se Deus assim nos amou, nós também devemos amar-nos uns aos outros.' },
      { v: 12, en: 'No one has seen God at any time. If we love one another, God remains in us, and his love has been perfected in us.', pt: 'Ninguém jamais viu a Deus; e nos amamos uns aos outros, Deus permanece em nós, e o seu amor é em nós aperfeiçoado.' },
      { v: 13, en: 'By this we know that we remain in him and he in us, because he has given us of his Spirit.', pt: 'Nisto conhecemos que permanecemos nele, e ele em nós: por ele nos ter dado do seu Espírito.' },
      { v: 14, en: 'We have seen and testify that the Father has sent the Son as the Savior of the world.', pt: 'E nós temos visto, e testificamos que o Pai enviou seu Filho como Salvador do mundo.' },
      { v: 15, en: 'Whoever confesses that Jesus is the Son of God, God remains in him, and he in God.', pt: 'Qualquer que confessar que Jesus é o Filho de Deus, Deus permanece nele, e ele em Deus.' },
      { v: 16, en: 'We know and have believed the love which God has for us. God is love, and he who remains in love remains in God, and God remains in him.', pt: 'E nós conhecemos, e cremos no amor que Deus nos tem. Deus é amor; e quem permanece em amor, permanece em Deus, e Deus nele.' },
      { v: 17, en: 'In this love has been made perfect among us, that we may have boldness in the day of judgment, because as he is, even so are we in this world.', pt: 'Nisto é aperfeiçoado em nós o amor, para que no dia do juízo tenhamos confiança; porque, qual ele é, somos também nós neste mundo.' },
      { v: 18, en: 'There is no fear in love; but perfect love casts out fear, because fear has punishment. He who fears is not made perfect in love.', pt: 'No amor não há medo antes o perfeito amor lança fora o medo; porque o medo envolve castigo; e quem tem medo não está aperfeiçoado no amor.' },
      { v: 19, en: 'We love him, because he first loved us.', pt: 'Nós amamos, porque ele nos amou primeiro.' },
      { v: 20, en: 'If a man says, “I love God,” and hates his brother, he is a liar; for he who doesn’t love his brother whom he has seen, how can he love God whom he has not seen?', pt: 'Se alguém diz: Eu amo a Deus, e odeia a seu irmão, é mentiroso. Pois quem não ama a seu irmão, ao qual viu, não pode amar a Deus, a quem não viu.' },
      { v: 21, en: 'This commandment we have from him, that he who loves God should also love his brother.', pt: 'E dele temos este mandamento, que quem ama a Deus ame também a seu irmão.' },
    ],
    5: [
      { v: 1, en: 'Whoever believes that Jesus is the Christ has been born of God. Whoever loves the Father also loves the child who is born of him.', pt: 'Todo aquele que crê que Jesus é o Cristo, é o nascido de Deus; e todo aquele que ama ao que o gerou, ama também ao que dele é nascido.' },
      { v: 2, en: 'By this we know that we love the children of God, when we love God and keep his commandments.', pt: 'Nisto conhecemos que amamos os filhos de Deus, se amamos a Deus e guardamos os seus mandamentos.' },
      { v: 3, en: 'For this is loving God, that we keep his commandments. His commandments are not grievous.', pt: 'Porque este é o amor de Deus, que guardemos os seus mandamentos; e os seus mandamentos não são penosos;' },
      { v: 4, en: 'For whatever is born of God overcomes the world. This is the victory that has overcome the world: your faith.', pt: 'porque todo o que é nascido de Deus vence o mundo; e esta é a vitória que vence o mundo: a nossa fé.' },
      { v: 5, en: 'Who is he who overcomes the world, but he who believes that Jesus is the Son of God?', pt: 'Quem é o que vence o mundo, senão aquele que crê que Jesus é o Filho de Deus?' },
      { v: 6, en: 'This is he who came by water and blood, Jesus Christ; not with the water only, but with the water and the blood. It is the Spirit who testifies, because the Spirit is the truth.', pt: 'Este é aquele que veio por água e sangue, isto é, Jesus Cristo; não só pela água, mas pela água e pelo sangue.' },
      { v: 7, en: 'For there are three who testify :', pt: 'E o Espírito é o que dá testemunho, porque o Espírito é a verdade.' },
      { v: 8, en: 'the Spirit, the water, and the blood; and the three agree as one.', pt: 'Porque três são os que dão testemunho: o Espírito, e a água, e o sangue; e estes três concordam.' },
      { v: 9, en: 'If we receive the witness of men, the witness of God is greater; for this is God’s testimony which he has testified concerning his Son.', pt: 'Se recebemos o testemunho dos homens, o testemunho de Deus é este, que de seu Filho testificou -' },
      { v: 10, en: 'He who believes in the Son of God has the testimony in himself. He who doesn’t believe God has made him a liar, because he has not believed in the testimony that God has given concerning his Son.', pt: 'Quem crê no Filho de Deus, em si mesmo tem o testemunho; quem a Deus não crê, mentiroso o fez; porquanto não creu no testemunho que Deus de seu Filho deu. -' },
      { v: 11, en: 'The testimony is this, that God gave to us eternal life, and this life is in his Son.', pt: 'E o testemunho é este: que Deus nos deu a vida eterna; e esta vida está em seu Filho.' },
      { v: 12, en: 'He who has the Son has the life. He who doesn’t have God’s Son doesn’t have the life.', pt: 'Quem tem o Filho tem a vida; quem não tem o Filho de Deus não tem a vida.' },
      { v: 13, en: 'These things I have written to you who believe in the name of the Son of God, that you may know that you have eternal life, and that you may continue to believe in the name of the Son of God.', pt: 'Estas coisas vos escrevo, a vós que credes no nome do Filho de Deus, para que saibais que tendes a vida eterna.' },
      { v: 14, en: 'This is the boldness which we have toward him, that, if we ask anything according to his will, he listens to us.', pt: 'E esta é a confiança que temos nele, que se pedirmos alguma coisa segundo a sua vontade, ele nos ouve.' },
      { v: 15, en: 'And if we know that he listens to us, whatever we ask, we know that we have the petitions which we have asked of him.', pt: 'e, se sabemos que nos ouve em tudo o que pedimos, sabemos que já alcançamos as coisas que lhe temos pedido.' },
      { v: 16, en: 'If anyone sees his brother sinning a sin not leading to death, he shall ask, and God will give him life for those who sin not leading to death. There is a sin leading to death. I don’t say that he should make a request concerning this.', pt: 'Se alguém vir seu irmão cometer um pecado que não é para morte, pedirá, e Deus lhe dará a vida para aqueles que não pecam para a morte. Há pecado para morte, e por esse não digo que ore.' },
      { v: 17, en: 'All unrighteousness is sin, and there is a sin not leading to death.', pt: 'Toda injustiça é pecado; e há pecado que não é para a morte.' },
      { v: 18, en: 'We know that whoever is born of God doesn’t sin, but he who was born of God keeps himself, and the evil one doesn’t touch him.', pt: 'Sabemos que todo aquele que é nascido de Deus não vive pecando; antes o guarda aquele que nasceu de Deus, e o Maligno não lhe toca.' },
      { v: 19, en: 'We know that we are of God, and the whole world lies in the power of the evil one.', pt: 'Sabemos que somos de Deus, e que o mundo inteiro jaz no Maligno.' },
      { v: 20, en: 'We know that the Son of God has come, and has given us an understanding, that we know him who is true, and we are in him who is true, in his Son Jesus Christ. This is the true God, and eternal life.', pt: 'Sabemos também que já veio o Filho de Deus, e nos deu entendimento para conhecermos aquele que é verdadeiro; e nós estamos naquele que é verdadeiro, isto é, em seu Filho Jesus Cristo. Este é o verdadeiro Deus e a vida eterna.' },
      { v: 21, en: 'Little children, keep yourselves from idols.', pt: 'Filhinhos, guardai-vos dos ídolos.' },
    ],
  },
};

export default book;
